/**
 * Profile generator - scaffolds performance profiling config and scripts
 * Creates: profile.config.ts, scripts/profile.sh
 */

import { resolve } from 'node:path';
import { writeFile, mkdir } from 'node:fs/promises';

export interface ProfileGeneratorResult {
  files: { path: string; action: 'created' | 'updated' }[];
}

/**
 * Generate profile config content
 */
export function generateProfileConfigContent(): string {
  return `/**
 * @platformatic/flame profiling configuration
 * @generated by @flusk/cli
 */
import { getLogger } from '@flusk/logger';

const logger = getLogger().child({ module: 'profile-config' });

export const profileConfig = {
  sourcemapDirs: ['./dist', './node_modules'],
  outputDir: './profiles',
  format: 'md' as const,
};

logger.debug({ config: profileConfig }, 'profile config loaded');
`;
}

/**
 * Generate profile shell script content
 */
export function generateProfileScriptContent(): string {
  return `#!/usr/bin/env bash
# Performance profiling wrapper script
# @generated by @flusk/cli
set -euo pipefail

DURATION=\${1:-30}
echo "🔥 Profiling for \${DURATION}s..."
node --import @flusk/otel ./dist/index.js &
PID=$!
sleep "\$DURATION"
kill -SIGINT "\$PID" 2>/dev/null || true
wait "\$PID" 2>/dev/null || true
echo "✅ Profile saved to ./profiles/"
`;
}

/**
 * Generate profiling scaffolding files
 */
export async function generateProfile(): Promise<ProfileGeneratorResult> {
  const root = process.cwd();
  const result: ProfileGeneratorResult = { files: [] };

  const configPath = 'profile.config.ts';
  await writeFile(
    resolve(root, configPath),
    generateProfileConfigContent(),
    'utf-8',
  );
  result.files.push({ path: configPath, action: 'created' });

  const scriptsDir = resolve(root, 'scripts');
  await mkdir(scriptsDir, { recursive: true });
  const scriptPath = 'scripts/profile.sh';
  await writeFile(
    resolve(root, scriptPath),
    generateProfileScriptContent(),
    { encoding: 'utf-8', mode: 0o755 },
  );
  result.files.push({ path: scriptPath, action: 'created' });

  return result;
}
